import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;

/**
 * SETTLE - an OCCURS table program with a strided subscript, translated
 * from COBOL 85. Defect variant: the strided index is off by one, so this
 * translation sums the ACCRUALS (odd positions, W-ITEM(2*I - 1)) instead of
 * the settlements. Any ledger whose accruals differ from its settlements
 * diverges - the classic table-stride indexing bug.
 */
public final class Settle {

    private static final BigDecimal RATE = new BigDecimal("2");
    private static final BigDecimal HUNDRED = new BigDecimal("100");
    private static final BigDecimal PIC_9_4_V99 = new BigDecimal("10000");
    private static final BigDecimal PIC_9_6_V99 = new BigDecimal("1000000");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        BigDecimal[] item = new BigDecimal[5]; // W-ITEM OCCURS 4 TIMES (1-based)
        item[1] = numval(in.readLine());
        item[2] = numval(in.readLine());
        item[3] = numval(in.readLine());
        item[4] = numval(in.readLine());

        // BUG: sums the odd positions (accruals) instead of the even ones.
        BigDecimal paid = BigDecimal.ZERO;
        for (int i = 1; i <= 2; i = i + 1) {
            paid = paid.add(item[2 * i - 1]).remainder(PIC_9_6_V99);
        }
        BigDecimal fee = paid.multiply(RATE).divide(HUNDRED).setScale(2, RoundingMode.HALF_UP).remainder(PIC_9_6_V99);

        StringBuilder out = new StringBuilder();
        out.append("PAID=").append(paid.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        out.append("FEE=").append(fee.setScale(2, RoundingMode.UNNECESSARY).toPlainString()).append('\n');
        System.out.print(out);
    }

    private static BigDecimal numval(String s) {
        try {
            return new BigDecimal(s.trim()).setScale(2, RoundingMode.DOWN).remainder(PIC_9_4_V99);
        } catch (NumberFormatException e) {
            System.err.println("SETTLE: invalid numeric input: " + s);
            System.exit(3);
            return BigDecimal.ZERO;
        }
    }
}
